  # MAV_CMD_DO_SET_MODE
  MAV_CMD_DO_SET_MODE = 176
  # Jump to the desired command in the mission list.  Repeat this action only the specified number of times
  # MAV_CMD_DO_JUMP
  MAV_CMD_DO_JUMP = 177
