# SERIAL_CONTROL flags (bitmask)
# SERIAL_CONTROL_FLAG
class SerialControlFlag(IntEnum):
  # Set if this is a reply
  # SERIAL_CONTROL_FLAG_REPLY
  SERIAL_CONTROL_FLAG_REPLY = 1
  # Set if the sender wants the receiver to send a response as another SERIAL_CONTROL message
  # SERIAL_CONTROL_FLAG_RESPOND
  SERIAL_CONTROL_FLAG_RESPOND = 2
  # Set if access to the serial port should be removed from whatever driver is currently using it, giving exclusive access to the SERIAL_CONTROL protocol. The port can be handed back by sending a request without this flag set
  # SERIAL_CONTROL_FLAG_EXCLUSIVE
  SERIAL_CONTROL_FLAG_EXCLUSIVE = 4
  # Block on writes to the serial port
  # SERIAL_CONTROL_FLAG_BLOCKING
  SERIAL_CONTROL_FLAG_BLOCKING = 8
  # Send multiple replies until port is drained
  # SERIAL_CONTROL_FLAG_MULTI
  SERIAL_CONTROL_FLAG_MULTI = 16

  @classmethod
  def from_value(cls, value: int) -> SerialControlFlag:
    # Exact match first
    for member in cls:
      if member.value == value:
        return member
    
    # For bitmasks, find the highest priority set bit
    sorted_members = sorted((m for m in cls if m.value > 0), key=lambda m: m.value, reverse=True)
    for member in sorted_members:
      if (value & member.value) != 0:
        return member
    
    return next((m for m in cls if m.value == 0), next(iter(cls)))
  


