# GOPRO_VIDEO_SETTINGS_FLAGS
class GoproVideoSettingsFlags(IntEnum):
  # 0=NTSC, 1=PAL.
  # GOPRO_VIDEO_SETTINGS_TV_MODE
  GOPRO_VIDEO_SETTINGS_TV_MODE = 1

  @classmethod
  def from_value(cls, value: int) -> GoproVideoSettingsFlags:
    # Exact match first
    for member in cls:
      if member.value == value:
        return member
    
    # For bitmasks, find the highest priority set bit
    sorted_members = sorted((m for m in cls if m.value > 0), key=lambda m: m.value, reverse=True)
    for member in sorted_members:
      if (value & member.value) != 0:
        return member
    
    return next((m for m in cls if m.value == 0), next(iter(cls)))
  


