# The heartbeat message shows that a system or component is present and responding. The type and autopilot fields (along with the message component id), allow the receiving system to treat further messages from this system appropriately (e.g. by laying out the user interface based on the autopilot). This microservice is documented at https://mavlink.io/en/services/heartbeat.html
# HEARTBEAT
@dataclass
class Heartbeat(MavlinkMessage):
  MSG_ID: ClassVar[int] = 0
  CRC_EXTRA: ClassVar[int] = 50
  MAVLINK_ENCODED_LENGTH: ClassVar[int] = 9

  @property
  def mavlink_message_id(self) -> int:
    return self.MSG_ID

  @property
  def mavlink_crc_extra(self) -> int:
    return self.CRC_EXTRA

  # A bitfield for use for autopilot-specific flags
  # MAVLink type: uint32_t
  # custom_mode
  custom_mode: uint32_t

  # Vehicle or component type. For a flight controller component the vehicle type (quadrotor, helicopter, etc.). For other components the component type (e.g. camera, gimbal, etc.). This should be used in preference to component id for identifying the component type.
  # MAVLink type: uint8_t
  # enum: [MavType]
  # type
  type: MavType

  # Autopilot type / class. Use MAV_AUTOPILOT_INVALID for components that are not flight controllers.
  # MAVLink type: uint8_t
  # enum: [MavAutopilot]
  # autopilot
  autopilot: MavAutopilot

  # System mode bitmap.
  # MAVLink type: uint8_t
  # enum: [MavModeFlag]
  # base_mode
  base_mode: uint8_t

  # System status flag.
  # MAVLink type: uint8_t
  # enum: [MavState]
  # system_status
  system_status: MavState

  # MAVLink version, not writable by user, gets added by protocol because of magic data type: uint8_t_mavlink_version
  # MAVLink type: uint8_t
  # mavlink_version
  mavlink_version: uint8_t

  def copy_with(self, **kwargs) -> Heartbeat:
    return replace(self, **kwargs)

  @classmethod
  def parse(cls, data_: bytes) -> Heartbeat:
    if len(data_) < cls.MAVLINK_ENCODED_LENGTH:
      data_ = data_ + bytes(cls.MAVLINK_ENCODED_LENGTH - len(data_))
    
    custom_mode = MavlinkMessage._get_uint32(data_, 0)
    type_raw = MavlinkMessage._get_uint8(data_, 4)
    type = MavType.from_value(type_raw)
    autopilot_raw = MavlinkMessage._get_uint8(data_, 5)
    autopilot = MavAutopilot.from_value(autopilot_raw)
    base_mode = MavlinkMessage._get_uint8(data_, 6)
    system_status_raw = MavlinkMessage._get_uint8(data_, 7)
    system_status = MavState.from_value(system_status_raw)
    mavlink_version = MavlinkMessage._get_uint8(data_, 8)

    return cls(
      custom_mode=custom_mode,
      type=type,
      autopilot=autopilot,
      base_mode=base_mode,
      system_status=system_status,
      mavlink_version=mavlink_version
    )
  

  def serialize(self) -> bytes:
    data_ = bytearray(self.MAVLINK_ENCODED_LENGTH)
    MavlinkMessage._set_uint32(data_, 0, self.custom_mode)
    MavlinkMessage._set_uint8(data_, 4, self.type.value)
    MavlinkMessage._set_uint8(data_, 5, self.autopilot.value)
    MavlinkMessage._set_uint8(data_, 6, self.base_mode)
    MavlinkMessage._set_uint8(data_, 7, self.system_status.value)
    MavlinkMessage._set_uint8(data_, 8, self.mavlink_version)
    return bytes(data_)
  


# The general system state. If the system is following the MAVLink standard, the system state is mainly defined by three orthogonal states/modes: The system mode, which is either LOCKED (motors shut down and locked), MANUAL (system under RC control), GUIDED (system with autonomous position control, position setpoint controlled manually) or AUTO (system guided by path/waypoint planner). The NAV_MODE defined the current flight state: LIFTOFF (often an open-loop maneuver), LANDING, WAYPOINTS or VECTOR. This represents the internal navigation state machine. The system status shows whether the system is currently active or not and if an emergency occurred. During the CRITICAL and EMERGENCY states the MAV is still considered to be active, but should start emergency procedures autonomously. After a failure occurred it should first move from active to critical to allow manual intervention and then move to emergency after a certain timeout.
# SYS_STATUS
@dataclass
class SysStatus(MavlinkMessage):
  MSG_ID: ClassVar[int] = 1
  CRC_EXTRA: ClassVar[int] = 124
  MAVLINK_ENCODED_LENGTH: ClassVar[int] = 31

  @property
  def mavlink_message_id(self) -> int:
    return self.MSG_ID

  @property
  def mavlink_crc_extra(self) -> int:
    return self.CRC_EXTRA

  # Bitmap showing which onboard controllers and sensors are present. Value of 0: not present. Value of 1: present.
  # MAVLink type: uint32_t
  # enum: [MavSysStatusSensor]
  # onboard_control_sensors_present
  onboard_control_sensors_present: uint32_t

  # Bitmap showing which onboard controllers and sensors are enabled:  Value of 0: not enabled. Value of 1: enabled.
  # MAVLink type: uint32_t
  # enum: [MavSysStatusSensor]
  # onboard_control_sensors_enabled
  onboard_control_sensors_enabled: uint32_t

  # Bitmap showing which onboard controllers and sensors have an error (or are operational). Value of 0: error. Value of 1: healthy.
  # MAVLink type: uint32_t
  # enum: [MavSysStatusSensor]
  # onboard_control_sensors_health
  onboard_control_sensors_health: uint32_t

  # Maximum usage in percent of the mainloop time. Values: [0-1000] - should always be below 1000
  # MAVLink type: uint16_t
  # units: d%
  # load
  load: uint16_t

  # Battery voltage, UINT16_MAX: Voltage not sent by autopilot
  # MAVLink type: uint16_t
  # units: mV
  # voltage_battery
  voltage_battery: uint16_t

  # Battery current, -1: Current not sent by autopilot
  # MAVLink type: int16_t
  # units: cA
  # current_battery
  current_battery: int16_t

  # Communication drop rate, (UART, I2C, SPI, CAN), dropped packets on all links (packets that were corrupted on reception on the MAV)
  # MAVLink type: uint16_t
  # units: c%
  # drop_rate_comm
  drop_rate_comm: uint16_t

  # Communication errors (UART, I2C, SPI, CAN), dropped packets on all links (packets that were corrupted on reception on the MAV)
  # MAVLink type: uint16_t
  # errors_comm
  errors_comm: uint16_t

  # Autopilot-specific errors
  # MAVLink type: uint16_t
  # errors_count1
  errors_count1: uint16_t

  # Autopilot-specific errors
  # MAVLink type: uint16_t
  # errors_count2
  errors_count2: uint16_t

  # Autopilot-specific errors
  # MAVLink type: uint16_t
  # errors_count3
  errors_count3: uint16_t

  # Autopilot-specific errors
  # MAVLink type: uint16_t
  # errors_count4
  errors_count4: uint16_t

  # Battery energy remaining, -1: Battery remaining energy not sent by autopilot
  # MAVLink type: int8_t
  # units: %
  # battery_remaining
  battery_remaining: int8_t

  def copy_with(self, **kwargs) -> SysStatus:
    return replace(self, **kwargs)

  @classmethod
  def parse(cls, data_: bytes) -> SysStatus:
    if len(data_) < cls.MAVLINK_ENCODED_LENGTH:
      data_ = data_ + bytes(cls.MAVLINK_ENCODED_LENGTH - len(data_))
    
    onboard_control_sensors_present = MavlinkMessage._get_uint32(data_, 0)
    onboard_control_sensors_enabled = MavlinkMessage._get_uint32(data_, 4)
    onboard_control_sensors_health = MavlinkMessage._get_uint32(data_, 8)
    load = MavlinkMessage._get_uint16(data_, 12)
    voltage_battery = MavlinkMessage._get_uint16(data_, 14)
    current_battery = MavlinkMessage._get_int16(data_, 16)
    drop_rate_comm = MavlinkMessage._get_uint16(data_, 18)
    errors_comm = MavlinkMessage._get_uint16(data_, 20)
    errors_count1 = MavlinkMessage._get_uint16(data_, 22)
    errors_count2 = MavlinkMessage._get_uint16(data_, 24)
    errors_count3 = MavlinkMessage._get_uint16(data_, 26)
    errors_count4 = MavlinkMessage._get_uint16(data_, 28)
    battery_remaining = MavlinkMessage._get_int8(data_, 30)

    return cls(
      onboard_control_sensors_present=onboard_control_sensors_present,
      onboard_control_sensors_enabled=onboard_control_sensors_enabled,
      onboard_control_sensors_health=onboard_control_sensors_health,
      load=load,
      voltage_battery=voltage_battery,
      current_battery=current_battery,
      drop_rate_comm=drop_rate_comm,
      errors_comm=errors_comm,
      errors_count1=errors_count1,
      errors_count2=errors_count2,
      errors_count3=errors_count3,
      errors_count4=errors_count4,
      battery_remaining=battery_remaining
    )
  

  def serialize(self) -> bytes:
    data_ = bytearray(self.MAVLINK_ENCODED_LENGTH)
    MavlinkMessage._set_uint32(data_, 0, self.onboard_control_sensors_present)
    MavlinkMessage._set_uint32(data_, 4, self.onboard_control_sensors_enabled)
    MavlinkMessage._set_uint32(data_, 8, self.onboard_control_sensors_health)
    MavlinkMessage._set_uint16(data_, 12, self.load)
    MavlinkMessage._set_uint16(data_, 14, self.voltage_battery)
    MavlinkMessage._set_int16(data_, 16, self.current_battery)
    MavlinkMessage._set_uint16(data_, 18, self.drop_rate_comm)
    MavlinkMessage._set_uint16(data_, 20, self.errors_comm)
    MavlinkMessage._set_uint16(data_, 22, self.errors_count1)
    MavlinkMessage._set_uint16(data_, 24, self.errors_count2)
    MavlinkMessage._set_uint16(data_, 26, self.errors_count3)
    MavlinkMessage._set_uint16(data_, 28, self.errors_count4)
    MavlinkMessage._set_int8(data_, 30, self.battery_remaining)
    return bytes(data_)
  


