# A ping message either requesting or responding to a ping. This allows to measure the system latencies, including serial port, radio modem and UDP connections. The ping microservice is documented at https://mavlink.io/en/services/ping.html
# PING
@dataclass
class Ping(MavlinkMessage):
  MSG_ID: ClassVar[int] = 4
  CRC_EXTRA: ClassVar[int] = 237
  MAVLINK_ENCODED_LENGTH: ClassVar[int] = 14

  @property
  def mavlink_message_id(self) -> int:
    return self.MSG_ID

  @property
  def mavlink_crc_extra(self) -> int:
    return self.CRC_EXTRA

  # Timestamp (UNIX Epoch time or time since system boot). The receiving end can infer timestamp format (since 1.1.1970 or since system boot) by checking for the magnitude of the number.
  # MAVLink type: uint64_t
  # units: us
  # time_usec
  time_usec: uint64_t

