  # MAVLink type: uint32_t
  # seq
  seq: uint32_t

  # 0: request ping from all receiving systems. If greater than 0: message is a ping response and number is the system id of the requesting system
  # MAVLink type: uint8_t
  # target_system
  target_system: uint8_t

  # 0: request ping from all receiving components. If greater than 0: message is a ping response and number is the component id of the requesting component.
  # MAVLink type: uint8_t
  # target_component
  target_component: uint8_t

  def copy_with(self, **kwargs) -> Ping:
    return replace(self, **kwargs)

  @classmethod
  def parse(cls, data_: bytes) -> Ping:
    if len(data_) < cls.MAVLINK_ENCODED_LENGTH:
      data_ = data_ + bytes(cls.MAVLINK_ENCODED_LENGTH - len(data_))
    
    time_usec = MavlinkMessage._get_uint64(data_, 0)
