    ygyro = MavlinkMessage._get_float32(data_, 24)
    zgyro = MavlinkMessage._get_float32(data_, 28)
    xmag = MavlinkMessage._get_float32(data_, 32)
    ymag = MavlinkMessage._get_float32(data_, 36)
    zmag = MavlinkMessage._get_float32(data_, 40)
    abs_pressure = MavlinkMessage._get_float32(data_, 44)
    diff_pressure = MavlinkMessage._get_float32(data_, 48)
