    MavlinkMessage._set_float32(data_, 24, self.ygyro)
    MavlinkMessage._set_float32(data_, 28, self.zgyro)
    MavlinkMessage._set_float32(data_, 32, self.xmag)
    MavlinkMessage._set_float32(data_, 36, self.ymag)
    MavlinkMessage._set_float32(data_, 40, self.zmag)
    MavlinkMessage._set_float32(data_, 44, self.abs_pressure)
