    remrssi = MavlinkMessage._get_uint8(data_, 5)
    txbuf = MavlinkMessage._get_uint8(data_, 6)
    noise = MavlinkMessage._get_uint8(data_, 7)
    remnoise = MavlinkMessage._get_uint8(data_, 8)

