    integrated_xgyro = MavlinkMessage._get_float32(data_, 20)
    integrated_ygyro = MavlinkMessage._get_float32(data_, 24)
    integrated_zgyro = MavlinkMessage._get_float32(data_, 28)
    time_delta_distance_us = MavlinkMessage._get_uint32(data_, 32)
    distance = MavlinkMessage._get_float32(data_, 36)
    temperature = MavlinkMessage._get_int16(data_, 40)
    sensor_id = MavlinkMessage._get_uint8(data_, 42)
    quality = MavlinkMessage._get_uint8(data_, 43)

