    MavlinkMessage._set_uint32(data_, 0, self.time_last_baseline_ms)
    MavlinkMessage._set_uint32(data_, 4, self.tow)
    MavlinkMessage._set_int32(data_, 8, self.baseline_a_mm)
    MavlinkMessage._set_int32(data_, 12, self.baseline_b_mm)
    MavlinkMessage._set_int32(data_, 16, self.baseline_c_mm)
    MavlinkMessage._set_uint32(data_, 20, self.accuracy)
    MavlinkMessage._set_int32(data_, 24, self.iar_num_hypotheses)
    MavlinkMessage._set_uint16(data_, 28, self.wn)
    MavlinkMessage._set_uint8(data_, 30, self.rtk_receiver_id)
