# Handshake message to initiate, control and stop image streaming when using the Image Transmission Protocol: https://mavlink.io/en/services/image_transmission.html.
# DATA_TRANSMISSION_HANDSHAKE
@dataclass
class DataTransmissionHandshake(MavlinkMessage):
  MSG_ID: ClassVar[int] = 130
  CRC_EXTRA: ClassVar[int] = 29
  MAVLINK_ENCODED_LENGTH: ClassVar[int] = 13

  @property
  def mavlink_message_id(self) -> int:
    return self.MSG_ID

  @property
  def mavlink_crc_extra(self) -> int:
    return self.CRC_EXTRA

  # total data size (set on ACK only).
  # MAVLink type: uint32_t
  # units: bytes
  # size
  size: uint32_t

  # Width of a matrix or image.
  # MAVLink type: uint16_t
  # width
  width: uint16_t

  # Height of a matrix or image.
  # MAVLink type: uint16_t
  # height
  height: uint16_t

  # Number of packets being sent (set on ACK only).
  # MAVLink type: uint16_t
  # packets
  packets: uint16_t

  # Type of requested/acknowledged data.
  # MAVLink type: uint8_t
  # enum: [MavlinkDataStreamType]
  # type
  type: MavlinkDataStreamType

  # Payload size per packet (normally 253 byte, see DATA field size in message ENCAPSULATED_DATA) (set on ACK only).
  # MAVLink type: uint8_t
  # units: bytes
  # payload
  payload: uint8_t

  # JPEG quality. Values: [1-100].
  # MAVLink type: uint8_t
  # units: %
  # jpg_quality
  jpg_quality: uint8_t

  def copy_with(self, **kwargs) -> DataTransmissionHandshake:
    return replace(self, **kwargs)

  @classmethod
  def parse(cls, data_: bytes) -> DataTransmissionHandshake:
    if len(data_) < cls.MAVLINK_ENCODED_LENGTH:
      data_ = data_ + bytes(cls.MAVLINK_ENCODED_LENGTH - len(data_))
    
    size = MavlinkMessage._get_uint32(data_, 0)
    width = MavlinkMessage._get_uint16(data_, 4)
    height = MavlinkMessage._get_uint16(data_, 6)
    packets = MavlinkMessage._get_uint16(data_, 8)
    type_raw = MavlinkMessage._get_uint8(data_, 10)
    type = MavlinkDataStreamType.from_value(type_raw)
    payload = MavlinkMessage._get_uint8(data_, 11)
    jpg_quality = MavlinkMessage._get_uint8(data_, 12)

    return cls(
      size=size,
      width=width,
      height=height,
      packets=packets,
      type=type,
      payload=payload,
      jpg_quality=jpg_quality
    )
  

  def serialize(self) -> bytes:
    data_ = bytearray(self.MAVLINK_ENCODED_LENGTH)
    MavlinkMessage._set_uint32(data_, 0, self.size)
    MavlinkMessage._set_uint16(data_, 4, self.width)
    MavlinkMessage._set_uint16(data_, 6, self.height)
    MavlinkMessage._set_uint16(data_, 8, self.packets)
    MavlinkMessage._set_uint8(data_, 10, self.type.value)
    MavlinkMessage._set_uint8(data_, 11, self.payload)
    MavlinkMessage._set_uint8(data_, 12, self.jpg_quality)
    return bytes(data_)
  


