    max_distance = MavlinkMessage._get_uint16(data_, 6)
    current_distance = MavlinkMessage._get_uint16(data_, 8)
    type_raw = MavlinkMessage._get_uint8(data_, 10)
    type = MavDistanceSensor.from_value(type_raw)
    id = MavlinkMessage._get_uint8(data_, 11)
    orientation_raw = MavlinkMessage._get_uint8(data_, 12)
