    if len(data_) < cls.MAVLINK_ENCODED_LENGTH:
      data_ = data_ + bytes(cls.MAVLINK_ENCODED_LENGTH - len(data_))
    
    breach_time = MavlinkMessage._get_uint32(data_, 0)
    breach_count = MavlinkMessage._get_uint16(data_, 4)
    breach_status = MavlinkMessage._get_uint8(data_, 6)
    breach_type_raw = MavlinkMessage._get_uint8(data_, 7)
    breach_type = FenceBreach.from_value(breach_type_raw)
    breach_mitigation_raw = MavlinkMessage._get_uint8(data_, 8)
    breach_mitigation = FenceMitigate.from_value(breach_mitigation_raw)

    return cls(
      breach_time=breach_time,
      breach_count=breach_count,
      breach_status=breach_status,
      breach_type=breach_type,
      breach_mitigation=breach_mitigation
    )
  

