    data_ = bytearray(self.MAVLINK_ENCODED_LENGTH)
    MavlinkMessage._set_uint32(data_, 0, self.breach_time)
    MavlinkMessage._set_uint16(data_, 4, self.breach_count)
    MavlinkMessage._set_uint8(data_, 6, self.breach_status)
    MavlinkMessage._set_uint8(data_, 7, self.breach_type.value)
    MavlinkMessage._set_uint8(data_, 8, self.breach_mitigation.value)
    return bytes(data_)
  


