  # MAVLink type: float
  # hagl_ratio
  hagl_ratio: float

  # True airspeed innovation test ratio
  # MAVLink type: float
  # tas_ratio
  tas_ratio: float

  # Horizontal position 1-STD accuracy relative to the EKF local origin
  # MAVLink type: float
  # units: m
  # pos_horiz_accuracy
  pos_horiz_accuracy: float

  # Vertical position 1-STD accuracy relative to the EKF local origin
  # MAVLink type: float
  # units: m
  # pos_vert_accuracy
  pos_vert_accuracy: float

  # Bitmap indicating which EKF outputs are valid.
  # MAVLink type: uint16_t
  # enum: [EstimatorStatusFlags]
  # flags
  flags: uint16_t

  def copy_with(self, **kwargs) -> EstimatorStatus:
    return replace(self, **kwargs)

  @classmethod
  def parse(cls, data_: bytes) -> EstimatorStatus:
    if len(data_) < cls.MAVLINK_ENCODED_LENGTH:
      data_ = data_ + bytes(cls.MAVLINK_ENCODED_LENGTH - len(data_))
    
    time_usec = MavlinkMessage._get_uint64(data_, 0)
    vel_ratio = MavlinkMessage._get_float32(data_, 8)
    pos_horiz_ratio = MavlinkMessage._get_float32(data_, 12)
    pos_vert_ratio = MavlinkMessage._get_float32(data_, 16)
    mag_ratio = MavlinkMessage._get_float32(data_, 20)
    hagl_ratio = MavlinkMessage._get_float32(data_, 24)
    tas_ratio = MavlinkMessage._get_float32(data_, 28)
    pos_horiz_accuracy = MavlinkMessage._get_float32(data_, 32)
    pos_vert_accuracy = MavlinkMessage._get_float32(data_, 36)
    flags = MavlinkMessage._get_uint16(data_, 40)

    return cls(
      time_usec=time_usec,
      vel_ratio=vel_ratio,
      pos_horiz_ratio=pos_horiz_ratio,
      pos_vert_ratio=pos_vert_ratio,
      mag_ratio=mag_ratio,
      hagl_ratio=hagl_ratio,
      tas_ratio=tas_ratio,
      pos_horiz_accuracy=pos_horiz_accuracy,
      pos_vert_accuracy=pos_vert_accuracy,
      flags=flags
    )
  

