# RTCM message for injecting into the onboard GPS (used for DGPS)
# GPS_RTCM_DATA
@dataclass
class GpsRtcmData(MavlinkMessage):
  MSG_ID: ClassVar[int] = 233
  CRC_EXTRA: ClassVar[int] = 35
  MAVLINK_ENCODED_LENGTH: ClassVar[int] = 182

  @property
  def mavlink_message_id(self) -> int:
    return self.MSG_ID

  @property
  def mavlink_crc_extra(self) -> int:
    return self.CRC_EXTRA

  # LSB: 1 means message is fragmented, next 2 bits are the fragment ID, the remaining 5 bits are used for the sequence ID. Messages are only to be flushed to the GPS when the entire message has been reconstructed on the autopilot. The fragment ID specifies which order the fragments should be assembled into a buffer, while the sequence ID is used to detect a mismatch between different buffers. The buffer is considered fully reconstructed when either all 4 fragments are present, or all the fragments before the first fragment with a non full payload is received. This management is used to ensure that normal GPS operation doesn't corrupt RTCM data, and to recover from a unreliable transport delivery order.
  # MAVLink type: uint8_t
  # flags
  flags: uint8_t

  # data length
  # MAVLink type: uint8_t
  # units: bytes
  # len
  len: uint8_t

  # RTCM message (may be fragmented)
  # MAVLink type: uint8_t[180]
  # data
  data: list[uint8_t]

  def copy_with(self, **kwargs) -> GpsRtcmData:
    return replace(self, **kwargs)

  @classmethod
  def parse(cls, data_: bytes) -> GpsRtcmData:
    if len(data_) < cls.MAVLINK_ENCODED_LENGTH:
      data_ = data_ + bytes(cls.MAVLINK_ENCODED_LENGTH - len(data_))
    
    flags = MavlinkMessage._get_uint8(data_, 0)
    len = MavlinkMessage._get_uint8(data_, 1)
    data = MavlinkMessage._get_uint8_list(data_, 2, 180)

    return cls(
      flags=flags,
      len=len,
      data=data
    )
  

  def serialize(self) -> bytes:
    data_ = bytearray(self.MAVLINK_ENCODED_LENGTH)
    MavlinkMessage._set_uint8(data_, 0, self.flags)
    MavlinkMessage._set_uint8(data_, 1, self.len)
    MavlinkMessage._set_uint8_list(data_, 2, self.data)
    return bytes(data_)
  


