    load_current = MavlinkMessage._get_float32(data_, 12)
    power_generated = MavlinkMessage._get_float32(data_, 16)
    bus_voltage = MavlinkMessage._get_float32(data_, 20)
    bat_current_setpoint = MavlinkMessage._get_float32(data_, 24)
