  # State of AP_Limits.
  # MAVLink type: uint8_t
  # enum: [LimitsState]
  # limits_state
  limits_state: LimitsState

  # AP_Limit_Module bitfield of enabled modules.
  # MAVLink type: uint8_t
  # enum: [LimitModule]
  # mods_enabled
  mods_enabled: uint8_t

  # AP_Limit_Module bitfield of required modules.
  # MAVLink type: uint8_t
  # enum: [LimitModule]
  # mods_required
  mods_required: uint8_t

  # AP_Limit_Module bitfield of triggered modules.
  # MAVLink type: uint8_t
  # enum: [LimitModule]
  # mods_triggered
  mods_triggered: uint8_t

  def copy_with(self, **kwargs) -> LimitsStatus:
    return replace(self, **kwargs)

  @classmethod
  def parse(cls, data_: bytes) -> LimitsStatus:
    if len(data_) < cls.MAVLINK_ENCODED_LENGTH:
      data_ = data_ + bytes(cls.MAVLINK_ENCODED_LENGTH - len(data_))
    
    last_trigger = MavlinkMessage._get_uint32(data_, 0)
    last_action = MavlinkMessage._get_uint32(data_, 4)
    last_recovery = MavlinkMessage._get_uint32(data_, 8)
    last_clear = MavlinkMessage._get_uint32(data_, 12)
    breach_count = MavlinkMessage._get_uint16(data_, 16)
    limits_state_raw = MavlinkMessage._get_uint8(data_, 18)
    limits_state = LimitsState.from_value(limits_state_raw)
    mods_enabled = MavlinkMessage._get_uint8(data_, 19)
    mods_required = MavlinkMessage._get_uint8(data_, 20)
    mods_triggered = MavlinkMessage._get_uint8(data_, 21)

    return cls(
      last_trigger=last_trigger,
      last_action=last_action,
      last_recovery=last_recovery,
      last_clear=last_clear,
      breach_count=breach_count,
      limits_state=limits_state,
      mods_enabled=mods_enabled,
      mods_required=mods_required,
      mods_triggered=mods_triggered
    )
  

  def serialize(self) -> bytes:
    data_ = bytearray(self.MAVLINK_ENCODED_LENGTH)
    MavlinkMessage._set_uint32(data_, 0, self.last_trigger)
    MavlinkMessage._set_uint32(data_, 4, self.last_action)
    MavlinkMessage._set_uint32(data_, 8, self.last_recovery)
    MavlinkMessage._set_uint32(data_, 12, self.last_clear)
    MavlinkMessage._set_uint16(data_, 16, self.breach_count)
    MavlinkMessage._set_uint8(data_, 18, self.limits_state.value)
    MavlinkMessage._set_uint8(data_, 19, self.mods_enabled)
    MavlinkMessage._set_uint8(data_, 20, self.mods_required)
    MavlinkMessage._set_uint8(data_, 21, self.mods_triggered)
    return bytes(data_)
  


