# A rally point. Used to set a point when from GCS -> MAV. Also used to return a point from MAV -> GCS.
# RALLY_POINT
@dataclass
class RallyPoint(MavlinkMessage):
  MSG_ID: ClassVar[int] = 175
  CRC_EXTRA: ClassVar[int] = 138
  MAVLINK_ENCODED_LENGTH: ClassVar[int] = 19

  @property
  def mavlink_message_id(self) -> int:
    return self.MSG_ID

  @property
  def mavlink_crc_extra(self) -> int:
    return self.CRC_EXTRA

  # Latitude of point.
  # MAVLink type: int32_t
  # units: degE7
  # lat
  lat: int32_t

  # Longitude of point.
  # MAVLink type: int32_t
  # units: degE7
  # lng
  lng: int32_t

  # Transit / loiter altitude relative to home.
  # MAVLink type: int16_t
  # units: m
  # alt
  alt: int16_t

  # Break altitude relative to home.
  # MAVLink type: int16_t
  # units: m
  # break_alt
  break_alt: int16_t

  # Heading to aim for when landing.
  # MAVLink type: uint16_t
  # units: cdeg
  # land_dir
  land_dir: uint16_t

  # System ID.
  # MAVLink type: uint8_t
  # target_system
  target_system: uint8_t

  # Component ID.
  # MAVLink type: uint8_t
  # target_component
  target_component: uint8_t

  # Point index (first point is 0).
  # MAVLink type: uint8_t
  # idx
  idx: uint8_t

  # Total number of points (for sanity checking).
  # MAVLink type: uint8_t
  # count
  count: uint8_t

  # Configuration flags.
  # MAVLink type: uint8_t
  # enum: [RallyFlags]
  # flags
  flags: uint8_t

  def copy_with(self, **kwargs) -> RallyPoint:
    return replace(self, **kwargs)

  @classmethod
  def parse(cls, data_: bytes) -> RallyPoint:
    if len(data_) < cls.MAVLINK_ENCODED_LENGTH:
      data_ = data_ + bytes(cls.MAVLINK_ENCODED_LENGTH - len(data_))
    
    lat = MavlinkMessage._get_int32(data_, 0)
    lng = MavlinkMessage._get_int32(data_, 4)
    alt = MavlinkMessage._get_int16(data_, 8)
    break_alt = MavlinkMessage._get_int16(data_, 10)
    land_dir = MavlinkMessage._get_uint16(data_, 12)
    target_system = MavlinkMessage._get_uint8(data_, 14)
    target_component = MavlinkMessage._get_uint8(data_, 15)
    idx = MavlinkMessage._get_uint8(data_, 16)
    count = MavlinkMessage._get_uint8(data_, 17)
    flags = MavlinkMessage._get_uint8(data_, 18)

    return cls(
      lat=lat,
      lng=lng,
      alt=alt,
      break_alt=break_alt,
      land_dir=land_dir,
      target_system=target_system,
      target_component=target_component,
      idx=idx,
      count=count,
      flags=flags
    )
  

  def serialize(self) -> bytes:
    data_ = bytearray(self.MAVLINK_ENCODED_LENGTH)
    MavlinkMessage._set_int32(data_, 0, self.lat)
    MavlinkMessage._set_int32(data_, 4, self.lng)
    MavlinkMessage._set_int16(data_, 8, self.alt)
    MavlinkMessage._set_int16(data_, 10, self.break_alt)
    MavlinkMessage._set_uint16(data_, 12, self.land_dir)
    MavlinkMessage._set_uint8(data_, 14, self.target_system)
    MavlinkMessage._set_uint8(data_, 15, self.target_component)
    MavlinkMessage._set_uint8(data_, 16, self.idx)
    MavlinkMessage._set_uint8(data_, 17, self.count)
    MavlinkMessage._set_uint8(data_, 18, self.flags)
    return bytes(data_)
  


