  def mavlink_crc_extra(self) -> int:
    return self.CRC_EXTRA

  # Log data block sequence number.
  # MAVLink type: uint32_t
  # enum: [MavRemoteLogDataBlockCommands]
  # seqno
  seqno: MavRemoteLogDataBlockCommands

  # System ID.
  # MAVLink type: uint8_t
  # target_system
  target_system: uint8_t

  # Component ID.
  # MAVLink type: uint8_t
  # target_component
