  # Compass being calibrated.
  # MAVLink type: uint8_t
  # compass_id
  compass_id: uint8_t

  # Bitmask of compasses being calibrated.
  # MAVLink type: uint8_t
  # cal_mask
  cal_mask: uint8_t

  # Calibration Status.
  # MAVLink type: uint8_t
  # enum: [MagCalStatus]
  # cal_status
  cal_status: MagCalStatus

  # Attempt number.
  # MAVLink type: uint8_t
  # attempt
  attempt: uint8_t

  # Completion percentage.
  # MAVLink type: uint8_t
  # units: %
  # completion_pct
  completion_pct: uint8_t

  # Bitmask of sphere sections (see http://en.wikipedia.org/wiki/Geodesic_grid).
  # MAVLink type: uint8_t[10]
  # completion_mask
  completion_mask: list[uint8_t]

  def copy_with(self, **kwargs) -> MagCalProgress:
    return replace(self, **kwargs)

  @classmethod
  def parse(cls, data_: bytes) -> MagCalProgress:
    if len(data_) < cls.MAVLINK_ENCODED_LENGTH:
      data_ = data_ + bytes(cls.MAVLINK_ENCODED_LENGTH - len(data_))
    
    direction_x = MavlinkMessage._get_float32(data_, 0)
    direction_y = MavlinkMessage._get_float32(data_, 4)
    direction_z = MavlinkMessage._get_float32(data_, 8)
    compass_id = MavlinkMessage._get_uint8(data_, 12)
    cal_mask = MavlinkMessage._get_uint8(data_, 13)
    cal_status_raw = MavlinkMessage._get_uint8(data_, 14)
    cal_status = MagCalStatus.from_value(cal_status_raw)
    attempt = MavlinkMessage._get_uint8(data_, 15)
    completion_pct = MavlinkMessage._get_uint8(data_, 16)
    completion_mask = MavlinkMessage._get_uint8_list(data_, 17, 10)

    return cls(
      direction_x=direction_x,
      direction_y=direction_y,
      direction_z=direction_z,
      compass_id=compass_id,
      cal_mask=cal_mask,
      cal_status=cal_status,
      attempt=attempt,
      completion_pct=completion_pct,
      completion_mask=completion_mask
    )
  

  def serialize(self) -> bytes:
    data_ = bytearray(self.MAVLINK_ENCODED_LENGTH)
    MavlinkMessage._set_float32(data_, 0, self.direction_x)
    MavlinkMessage._set_float32(data_, 4, self.direction_y)
    MavlinkMessage._set_float32(data_, 8, self.direction_z)
    MavlinkMessage._set_uint8(data_, 12, self.compass_id)
    MavlinkMessage._set_uint8(data_, 13, self.cal_mask)
    MavlinkMessage._set_uint8(data_, 14, self.cal_status.value)
    MavlinkMessage._set_uint8(data_, 15, self.attempt)
    MavlinkMessage._set_uint8(data_, 16, self.completion_pct)
    MavlinkMessage._set_uint8_list(data_, 17, self.completion_mask)
    return bytes(data_)
  


