  # path_lon
  path_lon: int32_t

  # Arc entry point, latitude.
  # MAVLink type: int32_t
  # units: degE7
  # arc_entry_lat
  arc_entry_lat: int32_t

  # Arc entry point, longitude.
  # MAVLink type: int32_t
  # units: degE7
  # arc_entry_lon
  arc_entry_lon: int32_t

  # Altitude.
  # MAVLink type: float
  # units: m
  # altitude
  altitude: float

  # Distance the aircraft expects to travel during the deepstall.
  # MAVLink type: float
  # units: m
  # expected_travel_distance
  expected_travel_distance: float

  # Deepstall cross track error (only valid when in DEEPSTALL_STAGE_LAND).
  # MAVLink type: float
  # units: m
  # cross_track_error
  cross_track_error: float

  # Deepstall stage.
  # MAVLink type: uint8_t
  # enum: [DeepstallStage]
  # stage
  stage: DeepstallStage

  def copy_with(self, **kwargs) -> Deepstall:
    return replace(self, **kwargs)

  @classmethod
  def parse(cls, data_: bytes) -> Deepstall:
    if len(data_) < cls.MAVLINK_ENCODED_LENGTH:
      data_ = data_ + bytes(cls.MAVLINK_ENCODED_LENGTH - len(data_))
    
    landing_lat = MavlinkMessage._get_int32(data_, 0)
    landing_lon = MavlinkMessage._get_int32(data_, 4)
    path_lat = MavlinkMessage._get_int32(data_, 8)
    path_lon = MavlinkMessage._get_int32(data_, 12)
    arc_entry_lat = MavlinkMessage._get_int32(data_, 16)
    arc_entry_lon = MavlinkMessage._get_int32(data_, 20)
    altitude = MavlinkMessage._get_float32(data_, 24)
    expected_travel_distance = MavlinkMessage._get_float32(data_, 28)
    cross_track_error = MavlinkMessage._get_float32(data_, 32)
    stage_raw = MavlinkMessage._get_uint8(data_, 36)
    stage = DeepstallStage.from_value(stage_raw)

    return cls(
      landing_lat=landing_lat,
      landing_lon=landing_lon,
      path_lat=path_lat,
      path_lon=path_lon,
      arc_entry_lat=arc_entry_lat,
      arc_entry_lon=arc_entry_lon,
      altitude=altitude,
      expected_travel_distance=expected_travel_distance,
      cross_track_error=cross_track_error,
      stage=stage
    )
  

  def serialize(self) -> bytes:
    data_ = bytearray(self.MAVLINK_ENCODED_LENGTH)
    MavlinkMessage._set_int32(data_, 0, self.landing_lat)
    MavlinkMessage._set_int32(data_, 4, self.landing_lon)
    MavlinkMessage._set_int32(data_, 8, self.path_lat)
    MavlinkMessage._set_int32(data_, 12, self.path_lon)
    MavlinkMessage._set_int32(data_, 16, self.arc_entry_lat)
    MavlinkMessage._set_int32(data_, 20, self.arc_entry_lon)
    MavlinkMessage._set_float32(data_, 24, self.altitude)
    MavlinkMessage._set_float32(data_, 28, self.expected_travel_distance)
    MavlinkMessage._set_float32(data_, 32, self.cross_track_error)
    MavlinkMessage._set_uint8(data_, 36, self.stage.value)
    return bytes(data_)
  


