  # MAVLink type: uint8_t
  # target_system
  target_system: uint8_t

  # Component ID.
  # MAVLink type: uint8_t
  # target_component
  target_component: uint8_t

  # Data length.
  # MAVLink type: uint8_t
  # data_length
  data_length: uint8_t

  # Signature length.
  # MAVLink type: uint8_t
  # sig_length
  sig_length: uint8_t

  # Signed data.
  # MAVLink type: uint8_t[220]
  # data
  data: list[uint8_t]

  def copy_with(self, **kwargs) -> SecureCommand:
    return replace(self, **kwargs)

  @classmethod
  def parse(cls, data_: bytes) -> SecureCommand:
    if len(data_) < cls.MAVLINK_ENCODED_LENGTH:
      data_ = data_ + bytes(cls.MAVLINK_ENCODED_LENGTH - len(data_))
    
    sequence = MavlinkMessage._get_uint32(data_, 0)
    operation_raw = MavlinkMessage._get_uint32(data_, 4)
    operation = SecureCommandOp.from_value(operation_raw)
    target_system = MavlinkMessage._get_uint8(data_, 8)
    target_component = MavlinkMessage._get_uint8(data_, 9)
    data_length = MavlinkMessage._get_uint8(data_, 10)
    sig_length = MavlinkMessage._get_uint8(data_, 11)
    data = MavlinkMessage._get_uint8_list(data_, 12, 220)

    return cls(
      sequence=sequence,
      operation=operation,
      target_system=target_system,
      target_component=target_component,
      data_length=data_length,
      sig_length=sig_length,
      data=data
    )
  

  def serialize(self) -> bytes:
    data_ = bytearray(self.MAVLINK_ENCODED_LENGTH)
    MavlinkMessage._set_uint32(data_, 0, self.sequence)
