    MavlinkMessage._set_uint8(data_, 9, self.target_component)
    MavlinkMessage._set_uint8(data_, 10, self.data_length)
    MavlinkMessage._set_uint8(data_, 11, self.sig_length)
    MavlinkMessage._set_uint8_list(data_, 12, self.data)
    return bytes(data_)
  


