class RtRcBatteryStatus(MavlinkMessage):
  MSG_ID: ClassVar[int] = 45002
  CRC_EXTRA: ClassVar[int] = 74
  MAVLINK_ENCODED_LENGTH: ClassVar[int] = 4

  @property
  def mavlink_message_id(self) -> int:
    return self.MSG_ID

  @property
  def mavlink_crc_extra(self) -> int:
    return self.CRC_EXTRA

  # Battery charge level of the remote control in percent (0-100).
  # MAVLink type: uint8_t
  # units: %
  # battery_level
  battery_level: uint8_t

  # Active charging flag: 0 - not charging; 1 - charging.
  # MAVLink type: uint8_t
  # units: %
  # battery_charging_status
  battery_charging_status: uint8_t

  # Temperature of the left battery cell of the remote control.
  # MAVLink type: uint8_t
  # units: %
  # battery_temperature_left
  battery_temperature_left: uint8_t

  # Temperature of the right battery cell of the remote control.
  # MAVLink type: uint8_t
  # units: %
  # battery_temperature_right
  battery_temperature_right: uint8_t

  def copy_with(self, **kwargs) -> RtRcBatteryStatus:
    return replace(self, **kwargs)

  @classmethod
  def parse(cls, data_: bytes) -> RtRcBatteryStatus:
    if len(data_) < cls.MAVLINK_ENCODED_LENGTH:
      data_ = data_ + bytes(cls.MAVLINK_ENCODED_LENGTH - len(data_))
    
    battery_level = MavlinkMessage._get_uint8(data_, 0)
    battery_charging_status = MavlinkMessage._get_uint8(data_, 1)
    battery_temperature_left = MavlinkMessage._get_uint8(data_, 2)
    battery_temperature_right = MavlinkMessage._get_uint8(data_, 3)

    return cls(
      battery_level=battery_level,
      battery_charging_status=battery_charging_status,
      battery_temperature_left=battery_temperature_left,
      battery_temperature_right=battery_temperature_right
    )
  

  def serialize(self) -> bytes:
    data_ = bytearray(self.MAVLINK_ENCODED_LENGTH)
    MavlinkMessage._set_uint8(data_, 0, self.battery_level)
    MavlinkMessage._set_uint8(data_, 1, self.battery_charging_status)
    MavlinkMessage._set_uint8(data_, 2, self.battery_temperature_left)
    MavlinkMessage._set_uint8(data_, 3, self.battery_temperature_right)
    return bytes(data_)
  


# Cancel a long running command.
# RT_RC_COMMAND_CANCEL
@dataclass
class RtRcCommandCancel(MavlinkMessage):
  MSG_ID: ClassVar[int] = 45003
  CRC_EXTRA: ClassVar[int] = 107
  MAVLINK_ENCODED_LENGTH: ClassVar[int] = 4

  @property
  def mavlink_message_id(self) -> int:
    return self.MSG_ID

  @property
  def mavlink_crc_extra(self) -> int:
    return self.CRC_EXTRA

  # ID of the cancelled command.
  # MAVLink type: uint16_t
  # enum: [MavCmd]
  # command
  command: MavCmd

  # System ID
  # MAVLink type: uint8_t
  # target_system
  target_system: uint8_t

  # Component ID
  # MAVLink type: uint8_t
  # target_component
  target_component: uint8_t

  def copy_with(self, **kwargs) -> RtRcCommandCancel:
    return replace(self, **kwargs)

  @classmethod
  def parse(cls, data_: bytes) -> RtRcCommandCancel:
    if len(data_) < cls.MAVLINK_ENCODED_LENGTH:
      data_ = data_ + bytes(cls.MAVLINK_ENCODED_LENGTH - len(data_))
    
    command_raw = MavlinkMessage._get_uint16(data_, 0)
    command = MavCmd.from_value(command_raw)
    target_system = MavlinkMessage._get_uint8(data_, 2)
    target_component = MavlinkMessage._get_uint8(data_, 3)

    return cls(
      command=command,
      target_system=target_system,
      target_component=target_component
    )
  

  def serialize(self) -> bytes:
    data_ = bytearray(self.MAVLINK_ENCODED_LENGTH)
    MavlinkMessage._set_uint16(data_, 0, self.command.value)
    MavlinkMessage._set_uint8(data_, 2, self.target_system)
    MavlinkMessage._set_uint8(data_, 3, self.target_component)
    return bytes(data_)
  


